def apply_translations():
    wb = openpyxl.load_workbook(XLSX_PATH)
    ws = wb.active

    rows = list(ws.iter_rows(min_row=2, values_only=True))
    updated = 0

    for row_idx, row in enumerate(rows):
        if row_idx not in TRANSLATIONS:
            continue
        t1, t2, t3 = TRANSLATIONS[row_idx]
        _, _, _, _, s1, existing_t1, s2, existing_t2, s3, existing_t3 = row

        changed = False
        new_t1 = existing_t1
        new_t2 = existing_t2
        new_t3 = existing_t3

        if s1 and not existing_t1 and t1:
            new_t1 = t1
            changed = True
        if s2 and not existing_t2 and t2:
            new_t2 = t2
            changed = True
        if s3 and not existing_t3 and t3:
            new_t3 = t3
            changed = True

        if changed:
            excel_row = row_idx + 2
            ws.cell(row=excel_row, column=6, value=new_t1)
            ws.cell(row=excel_row, column=8, value=new_t2)
            ws.cell(row=excel_row, column=10, value=new_t3)
            updated += 1

    wb.save(XLSX_PATH)
    print(f"Updated {updated} rows in {XLSX_PATH}")


if __name__ == "__main__":
    apply_translations()
